using UnityEngine;
using System.Reflection;
public class Script
{
    public static object Main()
    {
        var sb = new System.Text.StringBuilder();
        // Find DataManager type in all assemblies
        foreach (var asm in System.AppDomain.CurrentDomain.GetAssemblies())
        {
            foreach (var t in asm.GetTypes())
            {
                if (t.Name == "DataManager")
                {
                    sb.AppendLine("Found: " + t.FullName + " in " + asm.GetName().Name);
                    // Check for Instance property
                    var instProp = t.GetProperty("Instance", BindingFlags.Public | BindingFlags.Static);
                    if (instProp != null) { sb.AppendLine("  Has Instance property"); }
                    // List NPC-related fields
                    foreach (var f in t.GetFields(BindingFlags.NonPublic | BindingFlags.Instance | BindingFlags.Public | BindingFlags.Static))
                    {
                        if (f.Name.ToLower().Contains("npc")) sb.AppendLine("  field: " + f.Name + " type=" + f.FieldType.Name);
                    }
                }
            }
        }
        if (sb.Length == 0) sb.AppendLine("DataManager not found in any assembly");
        return sb.ToString();
    }
}
